// =============================================
// PREPARAR: Leer solicitud desde DB webhook, upsert org, UPDATE estado, build Apollo URL
// Dispara desde Supabase DB webhook (INSERT en solicitudes_leads)
// =============================================
const body = $input.first().json.body;
const input = body.record || body; // compat: DB webhook {record} o POST directo
const solicitudId = input.id || null;
const SB = 'https://azqtuvgtmmswvqgyrvct.supabase.co';
const SK = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImF6cXR1dmd0bW1zd3ZxZ3lydmN0Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzU5NTQ4NjEsImV4cCI6MjA5MTUzMDg2MX0.YRPD8A5SUcJt0EG7tZU-Q9EUzx8RT5RwbRe_jCVO-OQ';
const h = {'apikey':SK,'Authorization':'Bearer '+SK,'Content-Type':'application/json','Prefer':'return=representation'};

// 1. Upsert org si no viene organizacion_id
let organizacionId = input.organizacion_id || null;
if (!organizacionId) {
  try {
    const orgR = await $helpers.httpRequest({method:'POST',url:SB+'/rest/v1/organizaciones',headers:{...h,'Prefer':'return=representation,resolution=merge-duplicates'},body:JSON.stringify({nombre:input.organizacion||'Sin nombre',industria:input.industry||null,pais:input.company_country||input.person_country||null})});
    organizacionId = (Array.isArray(orgR)?orgR[0]:orgR)?.id||null;
  } catch(e){}
}

// 2. UPDATE solicitud (status processing + organizacion_id)
if (solicitudId) {
  try {
    await $helpers.httpRequest({method:'PATCH',url:SB+'/rest/v1/solicitudes_leads?id=eq.'+solicitudId,headers:h,body:JSON.stringify({status:'processing',organizacion_id:organizacionId})});
  } catch(e){}
}

// 3. Build Apollo URL
const sm={'C-Level':'c_suite','VP':'vp','Director':'director','Manager':'manager','Senior':'senior','Entry':'entry','c_suite':'c_suite','vp':'vp','director':'director','manager':'manager','senior':'senior','entry':'entry','intern':'intern'};
const p = [];
const mr = parseInt(input.max_results)||parseInt(input.cantidad_leads)||25;
p.push('per_page='+mr);
(Array.isArray(input.job_titles)?input.job_titles:[]).forEach(t=>{if(t?.trim())p.push('person_titles[]='+encodeURIComponent(t.trim()));});
if(input.include_similar&&Array.isArray(input.titulos_adicionales))input.titulos_adicionales.forEach(t=>{if(t?.trim())p.push('person_titles[]='+encodeURIComponent(t.trim()));});
(Array.isArray(input.seniority)?input.seniority:[]).forEach(s=>{const m=sm[s];if(m)p.push('person_seniorities[]='+m);});
(Array.isArray(input.departments)?input.departments:[]).forEach(d=>{if(d?.trim())p.push('person_departments[]='+encodeURIComponent(d.trim()));});
if(input.company_name)p.push('q_organization_name='+encodeURIComponent(input.company_name));
if(input.employee_min||input.employee_max)p.push('organization_num_employees_ranges[]='+encodeURIComponent((input.employee_min||1)+','+(input.employee_max||10000)));
const lp=[];if(input.company_city)lp.push(input.company_city);if(input.person_country)lp.push(input.person_country);else if(input.company_country)lp.push(input.company_country);
if(lp.length>0)p.push('person_locations[]='+encodeURIComponent(lp.join(', ')));
if(Array.isArray(input.keywords)&&input.keywords.length>0)p.push('q_keywords='+encodeURIComponent(input.keywords.join(' ')));

return [{json:{apolloUrl:'https://api.apollo.io/api/v1/mixed_people/api_search?'+p.join('&'),maxResults:mr,solicitudId,organizacionId,solucion:input.solucion||'',problema_resuelve:input.problema_resuelve||'',casos_exito:input.casos_exito||'',diferenciador:input.diferenciador||'',organizacion:input.organizacion||'',nombre_solicitante:input.nombre_completo||'',email_solicitante:input.email_corporativo||''}}];

// =============================================
// PROCESAR APOLLO → INSERT leads en Supabase
// Extrae TODOS los campos incluyendo org data
// =============================================
const items = $input.all();
const solicitudId = $node['Preparar1'].json.solicitudId;
const SB = 'https://azqtuvgtmmswvqgyrvct.supabase.co';
const SK = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImF6cXR1dmd0bW1zd3ZxZ3lydmN0Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzU5NTQ4NjEsImV4cCI6MjA5MTUzMDg2MX0.YRPD8A5SUcJt0EG7tZU-Q9EUzx8RT5RwbRe_jCVO-OQ';
const h = {'apikey':SK,'Authorization':'Bearer '+SK,'Content-Type':'application/json','Prefer':'return=representation'};

const results = [];
for (const item of items) {
  const p = item.json.person || item.json;
  const org = p.organization || {};

  // Fix LinkedIn URLs
  let liUrl = p.linkedin_url || '';
  if(liUrl.startsWith('http://')) liUrl = liUrl.replace('http://','https://');
  if(liUrl && !liUrl.includes('www.linkedin.com')) liUrl = liUrl.replace('linkedin.com','www.linkedin.com');
  let orgLi = org.linkedin_url || '';
  if(orgLi.startsWith('http://')) orgLi = orgLi.replace('http://','https://');

  // Build address
  const addr = [p.street_address, p.city, p.state, p.country].filter(Boolean).join(', ');

  const leadData = {
    solicitud_id: solicitudId,
    apollo_id: p.id || null,
    nombre: p.first_name || '',
    apellido: p.last_name || '',
    cargo: p.title || '',
    headline: p.headline || '',
    seniority: p.seniority || '',
    departamentos: (p.departments || []).join(', '),
    linkedin_url: liUrl,
    email: p.email || '',
    email_status: p.email_status || '',
    telefono: p.phone_numbers?.[0]?.sanitized_number || '',
    direccion: addr || null,
    ciudad: p.city || '',
    estado_region: p.state || '',
    pais: p.country || 'Chile',
    foto_url: p.photo_url || '',
    empresa: org.name || '',
    industria_empresa: org.industry || '',
    tamano_empresa: org.estimated_num_employees || null,
    website_empresa: org.website_url || '',
    linkedin_empresa: orgLi,
    org_keywords: org.keywords || null,
    org_short_description: org.short_description || null,
    org_technology_names: org.technology_names || null
  };

  let leadDbId = '';
  try {
    const resp = await $helpers.httpRequest({method:'POST',url:SB+'/rest/v1/leads',headers:h,body:JSON.stringify(leadData)});
    leadDbId = (Array.isArray(resp)?resp[0]:resp)?.id || '';
  } catch(e){}

  results.push({json:{...leadData, lead_db_id: leadDbId, 'Apollo ID': p.id||'', 'LinkedIn URL': liUrl}});
}
return results;

// LINKEDIN URL's — Limpia y normaliza URLs
const items = $input.all();
return items.map(item => {
  let url = item.json['LinkedIn URL'] || item.json.linkedin_url || '';
  url = url.trim();
  if(url.startsWith('http://')) url = url.replace('http://','https://');
  if(url && !url.startsWith('http')) url = 'https://'+url;
  if(url.includes('linkedin.com') && !url.includes('www.linkedin.com')) url = url.replace('linkedin.com','www.linkedin.com');
  let pubId = '';
  const match = url.match(/linkedin\.com\/in\/([^/?#]+)/);
  if(match) pubId = match[1];
  return {json:{...item.json, linkedinUrl:url, linkedinPublicIdentifier:pubId}};
});

// =============================================
// PARSEAR LINKEDIN → INSERT leads_linkedin en Supabase
// Extrae TODOS los campos nuevos
// =============================================
const items = $input.all();
const apolloItems = $('LinkedIn url\'s1').all();
const SB = 'https://azqtuvgtmmswvqgyrvct.supabase.co';
const SK = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImF6cXR1dmd0bW1zd3ZxZ3lydmN0Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzU5NTQ4NjEsImV4cCI6MjA5MTUzMDg2MX0.YRPD8A5SUcJt0EG7tZU-Q9EUzx8RT5RwbRe_jCVO-OQ';
const h = {'apikey':SK,'Authorization':'Bearer '+SK,'Content-Type':'application/json','Prefer':'return=minimal'};

const results = [];
for(let i=0;i<items.length;i++){
  const liRaw = Array.isArray(items[i].json) ? items[i].json[0] : items[i].json;
  const li = liRaw || {};
  const apollo = apolloItems[i]?.json || {};
  const leadDbId = apollo.lead_db_id || '';

  // Experience (top 5)
  const exp = Array.isArray(li.experience)
    ? li.experience.slice(0,5).map(e=>`${e.title||''} en ${e.companyName||''} (${e.duration||''})`).join(' | ')
    : '';
  // Education (top 3)
  const edu = Array.isArray(li.education)
    ? li.education.slice(0,3).map(e=>`${e.degreeName||''} ${e.fieldOfStudy||''} - ${e.schoolName||''}`).join(' | ')
    : '';
  // Skills
  const skills = Array.isArray(li.skills)
    ? li.skills.map(s=>typeof s==='string'?s:s.name||'').join(', ')
    : '';
  // Courses
  const courses = Array.isArray(li.courses)
    ? li.courses.map(c=>typeof c==='string'?c:c.name||'').join(', ')
    : '';
  // Projects
  const projects = Array.isArray(li.projects)
    ? li.projects.map(p=>`${p.title||''}: ${p.description||''}`).join(' | ')
    : '';
  // Publications
  const pubs = Array.isArray(li.publications)
    ? li.publications.map(p=>`${p.name||p.title||''}`).join(', ')
    : '';
  // Current position
  const curPos = Array.isArray(li.experience) && li.experience.length>0
    ? `${li.experience[0].title||''} en ${li.experience[0].companyName||''}`
    : '';

  const liData = {
    lead_id: leadDbId || null,
    linkedin_public_id: apollo.linkedinPublicIdentifier || '',
    linkedin_location: li.locationName || li.geoLocationName || li.location || '',
    headline: li.headline || '',
    summary: li.about || li.summary || '',
    experiencia: exp,
    educacion: edu,
    skills: skills,
    ubicacion: li.location || li.geoLocationName || '',
    conexiones: parseInt(li.connectionsCount) || null,
    seguidores: parseInt(li.followerCount || li.followersCount) || null,
    open_to_work: li.isOpenToWork || li.openToWork || false,
    courses: courses || null,
    hiring: li.isHiring || false,
    current_position: curPos || null,
    projects: projects || null,
    publications: pubs || null,
    recent_news: li.recentNews || null
  };

  if(leadDbId){
    try{await $helpers.httpRequest({method:'POST',url:SB+'/rest/v1/leads_linkedin',headers:h,body:JSON.stringify(liData)});}catch(e){}
  }

  results.push({json:{
    'Apollo ID': apollo['Apollo ID']||'',
    lead_db_id: leadDbId,
    'LI Headline': liData.headline,
    'LI Summary': liData.summary,
    'LI Experiencia': exp,
    'LI Educación': edu,
    'LI Skills': skills,
    'LI Ubicación': liData.ubicacion,
    'LI Conexiones': String(liData.conexiones||''),
    'LI Seguidores': String(liData.seguidores||''),
    'LI Open to Work': liData.open_to_work,
    'LI Courses': courses,
    'LI Current Position': curPos,
    'LI Projects': projects,
    'LI Publications': pubs,
    'LI Hiring': liData.hiring,
    'LI Recent News': liData.recent_news
  }});
}
return results;

